+auto normalize_http_url(std::string& url, bool tls_enabled) -> void {
+  if (not url.starts_with("http://") and not url.starts_with("https://")) {
+    url.insert(0, tls_enabled ? "https://" : "http://");
+  } else if (tls_enabled and url.starts_with("http://")) {
+    url.insert(4, "s");
+  }
+}
